# Pure viewport math keeps rapid wheel events coherent and cursor anchored.
write(
    "src/editor/canvasMath.ts",
    '''export interface CanvasPoint { x: number; y: number }\n\nexport function clampCanvasZoom(value: number, min = 20, max = 400) {\n  const finite = Number.isFinite(value) ? value : 100;\n  return Math.min(max, Math.max(min, finite));\n}\n\nexport function normalizeWheelDelta(deltaY: number, deltaMode: number) {\n  if (deltaMode === 1) return deltaY * 16;\n  if (deltaMode === 2) return deltaY * 800;\n  return deltaY;\n}\n\nexport function zoomFromWheel(currentZoom: number, deltaY: number) {\n  const current = clampCanvasZoom(currentZoom);\n  const next = current * Math.exp(-deltaY * 0.0015);\n  return Math.round(clampCanvasZoom(next) * 10) / 10;\n}\n\nexport function panForZoomAnchor(\n  pan: CanvasPoint,\n  pointerFromViewportCenter: CanvasPoint,\n  currentZoom: number,\n  nextZoom: number,\n): CanvasPoint {\n  const current = Math.max(0.0001, currentZoom);\n  const ratio = nextZoom / current;\n  return {\n    x: pan.x + (pointerFromViewportCenter.x - pan.x) * (1 - ratio),\n    y: pan.y + (pointerFromViewportCenter.y - pan.y) * (1 - ratio),\n  };\n}\n''',
)

write(
    "src/editor/CanvasStage.tsx",
    '''import React, { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";\nimport { Player, type PlayerRef } from "@remotion/player";\nimport { MotionComposition } from "../MotionComposition";\nimport { getActiveScene } from "../core/project";\nimport type { KurogiProject, Layer } from "../types";\nimport { Icon } from "../ui/Icon";\nimport { normalizeWheelDelta, panForZoomAnchor, zoomFromWheel } from "./canvasMath";\n\ninterface CanvasStageProps {\n  project: KurogiProject;\n  playerRef: React.RefObject<PlayerRef>;\n  selectedLayerId: string;\n  zoom: number;\n  playing: boolean;\n  showSafeArea: boolean;\n  onSelect: (id: string) => void;\n  onTransformCommit: (id: string, patch: Partial<Layer>) => void;\n  onTextCommit: (id: string, text: string) => void;\n  onZoomChange?: (zoom: number) => void;\n  onReplaceAsset?: (layerId: string, file: File) => void;\n  onDuplicateLayer?: (layerId: string) => void;\n  onDeleteLayer?: (layerId: string) => void;\n}\n\ntype PanGesture = {\n  pointerId: number;\n  startX: number;\n  startY: number;\n  originX: number;\n  originY: number;\n};\n\nexport function CanvasStage({\n  project,\n  playerRef,\n  selectedLayerId,\n  zoom,\n  playing: _playing,\n  showSafeArea,\n  onSelect,\n  onTransformCommit,\n  onTextCommit,\n  onZoomChange,\n  onReplaceAsset,\n  onDuplicateLayer,\n  onDeleteLayer,\n}: CanvasStageProps) {\n  const scene = getActiveScene(project);\n  const selectedLayer = selectedLayerId ? project.layers[selectedLayerId] ?? null : null;\n  const stageRef = useRef<HTMLElement>(null);\n  const viewportRef = useRef<HTMLDivElement>(null);\n  const replaceInputRef = useRef<HTMLInputElement>(null);\n  const panGestureRef = useRef<PanGesture | null>(null);\n  const callbacksRef = useRef({ onSelect, onTransformCommit, onTextCommit });\n  const zoomRef = useRef(zoom);\n  const panRef = useRef({ x: 0, y: 0 });\n  callbacksRef.current = { onSelect, onTransformCommit, onTextCommit };\n  const [available, setAvailable] = useState({ width: 900, height: 600 });\n  const [pan, setPan] = useState({ x: 0, y: 0 });\n  const [panning, setPanning] = useState(false);\n  const [contextMenu, setContextMenu] = useState<{ x: number; y: number } | null>(null);\n\n  useEffect(() => { zoomRef.current = zoom; }, [zoom]);\n  useEffect(() => { panRef.current = pan; }, [pan]);\n\n  useLayoutEffect(() => {\n    const stage = stageRef.current;\n    if (!stage) return;\n    const update = () => {\n      const rect = stage.getBoundingClientRect();\n      setAvailable({ width: Math.max(240, rect.width - 72), height: Math.max(180, rect.height - 88) });\n    };\n    update();\n    const observer = new ResizeObserver(update);\n    observer.observe(stage);\n    return () => observer.disconnect();\n  }, []);\n\n  const fitScale = Math.min(available.width / scene.width, available.height / scene.height);\n  const baseWidth = Math.max(1, scene.width * fitScale);\n  const baseHeight = Math.max(1, scene.height * fitScale);\n  const viewScale = Math.max(.2, Math.min(4, zoom / 100));\n\n  const stableSelect = useCallback((id: string) => callbacksRef.current.onSelect(id), []);\n  const stableTransformCommit = useCallback(\n    (id: string, patch: Partial<Layer>) => callbacksRef.current.onTransformCommit(id, patch),\n    [],\n  );\n  const stableTextCommit = useCallback(\n    (id: string, text: string) => callbacksRef.current.onTextCommit(id, text),\n    [],\n  );\n\n  const playerInputProps = useMemo(\n    () => ({\n      project,\n      selectedId: selectedLayerId,\n      onSelect: stableSelect,\n      onTransformCommit: stableTransformCommit,\n      onTextCommit: stableTextCommit,\n      editable: true,\n      showSelection: true,\n      showSafeArea,\n    }),\n    [project, selectedLayerId, showSafeArea, stableSelect, stableTextCommit, stableTransformCommit],\n  );\n\n  function updatePan(next: { x: number; y: number }) {\n    panRef.current = next;\n    setPan(next);\n  }\n\n  function beginPan(event: React.PointerEvent<HTMLElement>) {\n    if (event.button !== 1) return;\n    event.preventDefault();\n    event.stopPropagation();\n    event.currentTarget.setPointerCapture(event.pointerId);\n    const currentPan = panRef.current;\n    panGestureRef.current = {\n      pointerId: event.pointerId,\n      startX: event.clientX,\n      startY: event.clientY,\n      originX: currentPan.x,\n      originY: currentPan.y,\n    };\n    setPanning(true);\n    setContextMenu(null);\n  }\n\n  function movePan(event: React.PointerEvent<HTMLElement>) {\n    const gesture = panGestureRef.current;\n    if (!gesture || gesture.pointerId !== event.pointerId) return;\n    updatePan({\n      x: gesture.originX + event.clientX - gesture.startX,\n      y: gesture.originY + event.clientY - gesture.startY,\n    });\n  }\n\n  function finishPan(event: React.PointerEvent<HTMLElement>) {\n    const gesture = panGestureRef.current;\n    if (!gesture || gesture.pointerId !== event.pointerId) return;\n    panGestureRef.current = null;\n    setPanning(false);\n    if (event.currentTarget.hasPointerCapture(event.pointerId)) event.currentTarget.releasePointerCapture(event.pointerId);\n  }\n\n  function handleWheel(event: React.WheelEvent<HTMLElement>) {\n    setContextMenu(null);\n    event.preventDefault();\n    if (event.ctrlKey || event.metaKey) {\n      const viewport = viewportRef.current?.getBoundingClientRect();\n      if (!viewport) return;\n      const currentZoom = zoomRef.current;\n      const delta = normalizeWheelDelta(event.deltaY, event.deltaMode);\n      const nextZoom = zoomFromWheel(currentZoom, delta);\n      if (Math.abs(nextZoom - currentZoom) < .01) return;\n      const pointerFromViewportCenter = {\n        x: event.clientX - (viewport.left + viewport.width / 2),\n        y: event.clientY - (viewport.top + viewport.height / 2),\n      };\n      const nextPan = panForZoomAnchor(panRef.current, pointerFromViewportCenter, currentZoom, nextZoom);\n      zoomRef.current = nextZoom;\n      updatePan(nextPan);\n      onZoomChange?.(nextZoom);\n      return;\n    }\n    updatePan({ x: panRef.current.x - event.deltaX, y: panRef.current.y - event.deltaY });\n  }\n\n  function fitView() {\n    updatePan({ x: 0, y: 0 });\n    zoomRef.current = 100;\n    onZoomChange?.(100);\n  }\n\n  function openContextMenu(event: React.MouseEvent<HTMLElement>) {\n    if (!selectedLayer || (selectedLayer.type !== "image" && selectedLayer.type !== "svg")) return;\n    event.preventDefault();\n    const rect = stageRef.current?.getBoundingClientRect();\n    if (!rect) return;\n    setContextMenu({\n      x: Math.max(8, Math.min(rect.width - 220, event.clientX - rect.left)),\n      y: Math.max(48, Math.min(rect.height - 250, event.clientY - rect.top)),\n    });\n  }\n\n  const imageLayer = selectedLayer?.type === "image" ? selectedLayer : null;\n\n  return (\n    <section\n      className={`stage editor-stage navigable-stage ${panning ? "is-panning" : ""}`}\n      ref={stageRef}\n      onPointerDownCapture={beginPan}\n      onPointerMove={movePan}\n      onPointerUp={finishPan}\n      onPointerCancel={finishPan}\n      onWheel={handleWheel}\n      onContextMenu={openContextMenu}\n      onAuxClick={(event) => event.preventDefault()}\n      onMouseDown={() => contextMenu && setContextMenu(null)}\n    >\n      <input\n        ref={replaceInputRef}\n        hidden\n        type="file"\n        accept="image/png,image/jpeg,image/webp,image/svg+xml"\n        onChange={(event) => {\n          const file = event.currentTarget.files?.[0];\n          if (file && selectedLayerId) onReplaceAsset?.(selectedLayerId, file);\n          event.currentTarget.value = "";\n          setContextMenu(null);\n        }}\n      />\n      <div className="stage-top"><span>{scene.name}</span><span>{scene.width} × {scene.height} · {scene.fps} FPS</span></div>\n      <div className="canvas-viewport" ref={viewportRef}>\n        <div\n          aria-hidden="true"\n          style={{\n            position: "absolute",\n            left: "50%",\n            top: "50%",\n            width: baseWidth,\n            height: baseHeight,\n            transform: `translate(-50%, -50%) translate3d(${pan.x}px, ${pan.y}px, 0)`,\n            willChange: panning ? "transform" : undefined,\n          }}\n        >\n          <div\n            className="canvas-wrap stable-canvas-wrap"\n            style={{\n              width: baseWidth,\n              height: baseHeight,\n              transform: `scale(${viewScale})`,\n              transformOrigin: "center center",\n              willChange: "transform",\n            }}\n          >\n            <Player\n              ref={playerRef}\n              component={MotionComposition}\n              inputProps={playerInputProps}\n              durationInFrames={Math.max(1, Math.round(scene.duration * scene.fps))}\n              compositionWidth={scene.width}\n              compositionHeight={scene.height}\n              fps={scene.fps}\n              controls={false}\n              autoPlay={false}\n              loop\n              style={{ width: baseWidth, height: baseHeight }}\n            />\n          </div>\n        </div>\n      </div>\n      <div className="canvas-view-controls">\n        <button type="button" title="Fit canvas" onClick={fitView}><Icon name="frame" size={15} /></button>\n        <span>{Math.round(zoom)}%</span>\n      </div>\n      {contextMenu ? (\n        <div className="asset-context-menu" style={{ left: contextMenu.x, top: contextMenu.y }} onMouseDown={(event) => event.stopPropagation()}>\n          <strong>{selectedLayer?.name}</strong>\n          <button type="button" onClick={() => replaceInputRef.current?.click()}><Icon name="upload" size={15} />Replace asset</button>\n          {imageLayer ? <>\n            <button type="button" onClick={() => { onTransformCommit(imageLayer.id, { fit: "cover" } as Partial<Layer>); setContextMenu(null); }}><Icon name="frame" size={15} />Crop to fill</button>\n            <button type="button" onClick={() => { onTransformCommit(imageLayer.id, { fit: "contain" } as Partial<Layer>); setContextMenu(null); }}><Icon name="assets" size={15} />Fit inside</button>\n            <button type="button" onClick={() => { onTransformCommit(imageLayer.id, { fit: "fill" } as Partial<Layer>); setContextMenu(null); }}><Icon name="shapes" size={15} />Stretch to frame</button>\n          </> : null}\n          <span />\n          <button type="button" onClick={() => { onDuplicateLayer?.(selectedLayerId); setContextMenu(null); }}><Icon name="copy" size={15} />Duplicate</button>\n          <button type="button" className="danger-text" onClick={() => { onDeleteLayer?.(selectedLayerId); setContextMenu(null); }}><Icon name="trash" size={15} />Delete</button>\n        </div>\n      ) : null}\n    </section>\n  );\n}\n''',
)

write(
    "scripts/audit-text-canvas.mjs",
    '''import { createServer } from "vite";\n\nconst server = await createServer({\n  appType: "custom",\n  configFile: false,\n  logLevel: "error",\n  optimizeDeps: { noDiscovery: true },\n  server: { hmr: false, middlewareMode: true, watch: null },\n});\n\ntry {\n  const projectCore = await server.ssrLoadModule("/src/core/project.ts");\n  const textLayout = await server.ssrLoadModule("/src/core/textLayout.ts");\n  const canvasMath = await server.ssrLoadModule("/src/editor/canvasMath.ts");\n  const issues = [];\n\n  if (textLayout.normalizeTextVerticalAlign(undefined) !== "middle") issues.push("Missing vertical alignment must migrate to middle");\n  if (textLayout.textVerticalJustification("top") !== "flex-start") issues.push("Top text alignment mapping is invalid");\n  if (textLayout.textVerticalJustification("middle") !== "center") issues.push("Middle text alignment mapping is invalid");\n  if (textLayout.textVerticalJustification("bottom") !== "flex-end") issues.push("Bottom text alignment mapping is invalid");\n\n  const project = projectCore.createProject({ name: "Text audit", format: "square" });\n  const scene = projectCore.getActiveScene(project);\n  const layer = projectCore.createTextLayer(scene);\n  if (layer.style.verticalAlign !== "middle") issues.push("New text layers must start vertically centered");\n\n  const legacyProject = structuredClone(project);\n  legacyProject.layers[layer.id] = layer;\n  legacyProject.scenes[scene.id].layerIds = [layer.id];\n  delete legacyProject.layers[layer.id].style.verticalAlign;\n  const migrated = projectCore.normalizeProject(legacyProject);\n  if (migrated.layers[layer.id].style.verticalAlign !== "middle") issues.push("Legacy text layers did not migrate to middle alignment");\n\n  const currentZoom = 100;\n  const nextZoom = canvasMath.zoomFromWheel(currentZoom, -120);\n  if (!(nextZoom > currentZoom)) issues.push("Wheel-up zoom must increase zoom");\n  const pan = { x: 37, y: -24 };\n  const pointer = { x: 180, y: 95 };\n  const nextPan = canvasMath.panForZoomAnchor(pan, pointer, currentZoom, nextZoom);\n  const before = { x: (pointer.x - pan.x) / (currentZoom / 100), y: (pointer.y - pan.y) / (currentZoom / 100) };\n  const after = { x: (pointer.x - nextPan.x) / (nextZoom / 100), y: (pointer.y - nextPan.y) / (nextZoom / 100) };\n  const anchorError = Math.hypot(after.x - before.x, after.y - before.y);\n  if (anchorError > 1e-7) issues.push(`Cursor anchor drifted by ${anchorError}`);\n  if (canvasMath.zoomFromWheel(400, -1000) !== 400) issues.push("Maximum canvas zoom clamp failed");\n  if (canvasMath.zoomFromWheel(20, 1000) !== 20) issues.push("Minimum canvas zoom clamp failed");\n\n  if (issues.length) {\n    console.error("Text/canvas foundation audit failed:");\n    for (const issue of issues) console.error(`- ${issue}`);\n    process.exitCode = 1;\n  } else {\n    console.log("Text/canvas foundation audit passed: 2D text alignment, migration, cursor anchoring, and zoom clamps are valid.");\n  }\n} finally {\n  await server.close();\n}\n''',
)

